)

# Due to capitalisation issues in the ISO, UnrealGold requires some staging to fix the file paths
# shellcheck disable=SC2034 # Used in sourced script
UNPACK_REQUEST_STAGING="on"
installer_step::unpack_iso::post_staging() {
  INSTALL_PATH="${1}"
  STAGING_PATH="${2}"

  # Fix capitalisation of folders
  mkdir -p "${INSTALL_PATH}/Help"
  mkdir -p "${INSTALL_PATH}/Manuals"
  mkdir -p "${INSTALL_PATH}/Maps"
  mkdir -p "${INSTALL_PATH}/Music"
  mkdir -p "${INSTALL_PATH}/Sounds"
  mkdir -p "${INSTALL_PATH}/System"
  mkdir -p "${INSTALL_PATH}/Textures"

  cp -rf "${STAGING_PATH}/HELP/"* "${INSTALL_PATH}/Help/"
  cp -rf "${STAGING_PATH}/MANUALS/"* "${INSTALL_PATH}/Manuals/"
  cp -rf "${STAGING_PATH}/MAPS/"* "${INSTALL_PATH}/Maps/"
  cp -rf "${STAGING_PATH}/MUSIC/"* "${INSTALL_PATH}/Music/"
  cp -rf "${STAGING_PATH}/SOUNDS/"* "${INSTALL_PATH}/Sounds/"
  cp -rf "${STAGING_PATH}/SYSTEM/"* "${INSTALL_PATH}/System/"
  cp -rf "${STAGING_PATH}/TEXTURES/"* "${INSTALL_PATH}/Textures/"
}

